from hypothesis import given, integers, lists

# Property 1: Adding zero doesn't change value
@given(integers())
def test_add_zero(x):
    assert x + 0 == x

# Property 2: Multiplication is commutative
@given(integers(), integers())
def test_multiplication_commutative(a, b):
    assert a * b == b * a

# Property 3: Sorting is stable (sorted once = sorted twice)
@given(lists(integers()))
def test_sort_stability(items):
    sorted_once = sorted(items)
    sorted_twice = sorted(sorted_once)
    assert sorted_once == sorted_twice

# Property 4: Sorted list is monotonic (each element <= next)
@given(lists(integers()))
def test_sorted_monotonic(items):
    sorted_list = sorted(items)
    for i in range(len(sorted_list) - 1):
        assert sorted_list[i] <= sorted_list[i + 1]

# Property 5: Reverse twice = original
@given(lists(integers()))
def test_reverse_stability(items):
    reversed_once = items[::-1]
    reversed_twice = reversed_once[::-1]
    assert reversed_twice == items

