import jqwik.api.API;

public class SortingProperties {

    @API
    void sortStability(@ForAll List<Integer> items) {
        List<Integer> sortedOnce = sort(items);
        List<Integer> sortedTwice = sort(sortedOnce);

        // Property: Sorting is stable
        Assertions.assertEquals(sortedOnce, sortedTwice);
    }

    @API
    void sortMonotonicity(@ForAll List<Integer> items) {
        List<Integer> sorted = sort(items);

        // Property: Sorted list is monotonic
        for (int i = 0; i < sorted.size() - 1; i++) {
            Assertions.assertTrue(sorted.get(i) <= sorted.get(i + 1));
        }
    }
}

