from hypothesis import given, settings, HealthCheck
from hypothesis import strategies as st
from hypothesis.stateful import (
    RuleBasedStateMachine, Bundle, rule, initialize, invariant
)


class OrderBookMachine(RuleBasedStateMachine):
    """
    Stateful property-based test for a limit order book.
    Each rule models one operation (place, cancel, match).
    Invariants are checked after every step.
    """

    def __init__(self):
        super().__init__()
        self.book = OrderBook()   # System under test
        self.reference = {}       # Simple dict tracking known orders

    # Hypothesis will call initialize before any rules
    @initialize(price=st.integers(min_value=1, max_value=10000),
                quantity=st.integers(min_value=1, max_value=1000))
    def place_buy(self, price, quantity):
        order_id = self.book.place_buy(price, quantity)
        self.reference[order_id] = ("buy", price, quantity)
        return order_id

    @rule(order_id=Bundle("orders"))
    def cancel_order(self, order_id):
        if order_id in self.reference:
            self.book.cancel(order_id)
            del self.reference[order_id]

    @invariant()
    def total_quantity_consistent(self):
        # Invariant: book's total buy quantity must match our reference
        expected = sum(q for (side, p, q) in self.reference.values()
                       if side == "buy")
        assert self.book.total_buy_quantity() == expected, (
            f"Mismatch: book has {self.book.total_buy_quantity()}, "
            f"reference has {expected}"
        )

    @invariant()
    def best_bid_is_max_price(self):
        buy_prices = [p for (side, p, q) in self.reference.values()
                      if side == "buy"]
        if buy_prices:
            assert self.book.best_bid() == max(buy_prices)


