from hypothesis import given, settings
from hypothesis import strategies as st
import json
from typing import Any


# Hypothesis has built-in recursive JSON strategy
json_strategy = st.recursive(
    base=st.one_of(
        st.none(),
        st.booleans(),
        st.integers(),
        st.floats(allow_nan=False, allow_infinity=False),
        st.text(),
    ),
    extend=lambda children: st.one_of(
        st.lists(children, max_size=10),
        st.dictionaries(st.text(), children, max_size=10),
    ),
    max_leaves=50,
)


def parse_event_payload(data: dict) -> dict:
    """Production parser: must handle any well-formed JSON without crashing."""
    if not isinstance(data, dict):
        raise ValueError("Payload must be a JSON object")
    event_type = data.get("type", "unknown")
    timestamp = data.get("timestamp")
    if timestamp is not None and not isinstance(timestamp, (int, float)):
        raise ValueError(f"timestamp must be numeric, got {type(timestamp)}")
    return {
        "event_type": str(event_type),
        "timestamp": float(timestamp) if timestamp is not None else None,
        "payload_keys": sorted(str(k) for k in data.keys()),
    }


# Property: parser must never crash with unexpected output — only succeed or raise ValueError
@given(json_strategy)
@settings(max_examples=1000)
def test_parser_never_crashes(data):
    try:
        result = parse_event_payload(data)
        # If it succeeds, result must be a well-formed dict
        assert isinstance(result, dict)
        assert "event_type" in result
        assert isinstance(result["payload_keys"], list)
    except ValueError:
        pass  # Explicit rejection is acceptable
    except Exception as e:
        # Any OTHER exception is a bug
        raise AssertionError(f"Parser crashed unexpectedly: {e!r}") from e


# Property: parsing a valid payload must produce consistent output
@given(st.text(max_size=50), st.floats(min_value=0, max_value=1e15,
                                         allow_nan=False, allow_infinity=False))
def test_valid_payload_round_trip(event_type, ts):
    payload = {"type": event_type, "timestamp": ts, "extra": "ignored"}
    result = parse_event_payload(payload)
    assert result["event_type"] == str(event_type)
    assert abs(result["timestamp"] - ts) < 1e-6

