# Control number of examples in CI vs thorough runs
THOROUGH = False  # Set True for nightly CI or pre-release

@settings(
    max_examples=10000 if THOROUGH else 100,
    suppress_health_check=[HealthCheck.too_slow],  # Allow slow strategies
    deadline=None,  # Disable per-example time limit in CI
)
@given(st.lists(st.integers(), min_size=0, max_size=10000))
def test_sort_properties_thorough(lst):
    """Run 10x more examples in thorough mode for pre-release."""
    result = sorted(lst)
    assert len(result) == len(lst)
    assert all(result[i] <= result[i+1] for i in range(len(result)-1))


# Use @example to ensure specific cases always run alongside random ones
from hypothesis import example

@example([])          # Always test empty list
@example([1])         # Always test single element
@example([2, 1, 2])   # Always test duplicates
@given(st.lists(st.integers()))
def test_sort_with_fixed_examples(lst):
    result = sorted(lst)
    assert len(result) == len(lst)
    if len(result) > 1:
        assert all(result[i] <= result[i+1] for i in range(len(result)-1))


